package com.assetflow.nexora.entity;
import jakarta.persistence.*; import java.math.*; import java.time.*; @Entity @Table(name="assets") public class Asset extends AuditedEntity { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="asset_id") public Long id; @Column(name="asset_tag",nullable=false,unique=true,length=30) public String assetTag; @Column(nullable=false,length=150) public String name; @Column(name="category_id",nullable=false) public Long categoryId; @Column(name="serial_number",length=100) public String serialNumber; @Column(name="qr_code",unique=true,length=150) public String qrCode; @Column(name="acquisition_date") public LocalDate acquisitionDate; @Column(name="acquisition_cost",precision=14,scale=2) public BigDecimal acquisitionCost; @Column(name="condition",nullable=false,length=20) public String condition="New"; @Column(length=150) public String location; @Column(nullable=false,length=30) public String status="Available"; @Column(name="is_bookable",nullable=false) public boolean bookable; @Column(name="owning_department_id") public Long owningDepartmentId; @Column(name="created_by",nullable=false) public Long createdBy; }
